INSERT INTO parks (name, region, park_type, address_line, city, state, zip_code, hours, total_fields, max_capacity, amenities, description, image_url, image_alt, card_summary, latitude, longitude, is_featured) VALUES
('Jones Beach State Park', 'Long Island', 'Beach', '1 Ocean Pkwy', 'Wantagh', 'NY', '11793', '6:00 AM - 10:00 PM', 2, 250, 'Boardwalk, concerts, beaches, parking', 'Oceanfront boardwalk, summer concerts, family activities, and wide sandy beaches.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1200&q=80', 'Sandy beach and ocean waves at sunset', 'Oceanfront boardwalk, beaches, concerts, and family-friendly summer events.', 40.596200, -73.503000, 1),
('Letchworth State Park', 'Western New York', 'Waterfalls', '1 Letchworth State Park', 'Castile', 'NY', '14427', '6:00 AM - 11:00 PM', 1, 180, 'Trails, overlooks, picnic areas', 'Dramatic gorge views, trails, scenic overlooks, and some of the state''s most iconic waterfalls.', 'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1200&q=80', 'Forest trail with scenic overlook', 'Gorge views, waterfall hikes, picnic areas, and outdoor programs.', 42.673000, -78.004800, 1),
('Niagara Falls State Park', 'Western New York', 'Landmark', '332 Prospect St', 'Niagara Falls', 'NY', '14303', 'Open daily', 1, 220, 'Observation decks, visitors center', 'World-famous waterfalls, observation decks, and unforgettable sightseeing experiences.', 'https://images.unsplash.com/photo-1528909514045-2fa4ac7a08ba?auto=format&fit=crop&w=1200&q=80', 'Waterfall mist and scenic overlook', 'Iconic waterfall views, visitor facilities, and special-event spaces.', 43.082800, -79.074200, 1),
('Watkins Glen State Park', 'Finger Lakes', 'Hiking', '1009 N Franklin St', 'Watkins Glen', 'NY', '14891', '8:00 AM - dusk', 1, 120, 'Gorge trails, waterfalls, scenic routes', 'Stone bridges, layered waterfalls, gorge trails, and one of New York''s signature hikes.', 'https://images.unsplash.com/photo-1506744038136-46273834b3fb?auto=format&fit=crop&w=1200&q=80', 'Gorge trail with waterfall', 'Stone bridges, waterfall trails, and scenic visitor experiences.', 42.380100, -76.873300, 1),
('Montauk Point State Park', 'Long Island', 'Coastal', '2000 Montauk Hwy', 'Montauk', 'NY', '11954', 'Sunrise - sunset', 1, 150, 'Lighthouse, trails, fishing', 'Clifftop views, striped lighthouse scenery, fishing spots, and dramatic coastal landscapes.', 'https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?auto=format&fit=crop&w=1200&q=80', 'Coastal cliffs near a lighthouse', 'Lighthouse scenery, fishing access, coastal trails, and sunrise views.', 41.072200, -71.860300, 0),
('Minnewaska State Park Preserve', 'Hudson Valley', 'Trails', '5281 Route 44-55', 'Kerhonkson', 'NY', '12446', '9:00 AM - 7:00 PM', 1, 140, 'Lakes, cliffs, carriage roads', 'Ridge-top views, lakes, cliffs, carriage roads, and peaceful hiking routes.', 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?auto=format&fit=crop&w=1200&q=80', 'Wooded trail through tall trees', 'Ridge views, lakes, carriage roads, and quiet hiking routes.', 41.739200, -74.234900, 0);
